  "name": "Mary's Pizzaria Online",
  "description": "Aplicativo de pedidos online para a Mary's Pizzaria com sistema de meio a meio, combos e integração com WhatsApp.",
  "requestFramePermissions": ["geolocation"]
}

export type Category = 'PIZZA' | 'COMBO' | 'BEVERAGE';

export interface Product {
  id: string;
  name: string;
  price: number;
  ingredients?: string;
  imageUrl: string;
  category: Category;
}

export interface OrderItem {
  id: string;
  product1: Product;
  product2?: Product; // For half-and-half
  quantity: number;
  observations: string;
  totalPrice: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  address: string;
}

export interface OrderHistory {
  orderNumber: string;
  items: OrderItem[];
  customer: CustomerData;
  date: string;
}

import { Product } from './types';

export const PIZZARIA_CONFIG = {
  name: "Mary's Pizzaria",
  phone: "81 9 91851200",
  whatsapp: "5581991851200",
  address: "Rua dr. Sebastião Amaral, 1203 Pau Amarelo",
  logoUrl: "https://images2.imgbox.com/39/1b/K8S9hP0H_o.png", // The provided logo URL
  colors: {
    orange: "#f97316",
    yellow: "#facc15",
    black: "#0f0f0f"
  }
};

