export const MENU_COMBOS: Product[] = [
  { id: 'c1', name: 'Combo 2 Pizzas + Batata + Kuat 2L', price: 69.90, ingredients: '2 pizzas (escolha os sabores), 1 porção de batata frita e 1 refrigerante Kuat 2L', imageUrl: 'https://images.unsplash.com/photo-1528137858148-d0180c574559?auto=format&fit=crop&q=80&w=400', category: 'COMBO' },
