import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { PIZZARIA_CONFIG, MENU_PIZZAS, MENU_COMBOS, MENU_BEVERAGES } from './constants';
import { Product, OrderItem, CustomerData, OrderHistory } from './types';

// Helper Components
const ProductCard: React.FC<{ 
  product: Product; 
  onSelect: (p: Product) => void 
}> = ({ product, onSelect }) => (
  <div 
    onClick={() => onSelect(product)}
    className="bg-zinc-900 rounded-xl overflow-hidden shadow-lg border border-zinc-800 transition-transform active:scale-95 cursor-pointer flex flex-col"
  >
    <img src={product.imageUrl} alt={product.name} className="h-40 w-full object-cover" />
    <div className="p-4 flex-1 flex flex-col justify-between">
      <div>
        <h3 className="text-lg font-bold text-orange-500">{product.name}</h3>
        {product.ingredients && <p className="text-xs text-zinc-400 mt-1 line-clamp-2">{product.ingredients}</p>}
      </div>
      <div className="mt-4 flex items-center justify-between">
        <span className="text-xl font-bold text-yellow-400">R$ {product.price.toFixed(2).replace('.', ',')}</span>
        <button className="bg-orange-600 hover:bg-orange-700 text-white px-3 py-1 rounded-full text-sm font-semibold">
          Adicionar
        </button>
      </div>
    </div>
  </div>
);

export default function App() {
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [view, setView] = useState<'menu' | 'selection' | 'checkout'>('menu');
  const [flavorMode, setFlavorMode] = useState<1 | 2>(1);
  const [selectedFlavors, setSelectedFlavors] = useState<Product[]>([]);
  const [observations, setObservations] = useState('');
  const [customer, setCustomer] = useState<CustomerData>({ name: '', phone: '', address: '' });
  const [lastOrder, setLastOrder] = useState<OrderHistory | null>(null);

  // Load history
  useEffect(() => {
    const history = localStorage.getItem('marys_pizzaria_history');
    if (history) {
      setLastOrder(JSON.parse(history));
    }
  }, []);

  const addToCart = (product: Product) => {
    // If simple product (beverage or combo not needing flavor selection logic)
    if (product.category !== 'PIZZA') {
       const newItem: OrderItem = {
         id: Math.random().toString(36).substr(2, 9),
         product1: product,
         quantity: 1,
         observations: '',
         totalPrice: product.price
       };
       setCart([...cart, newItem]);
    } else {
       // Start selection flow for pizza
       setFlavorMode(1);
       setSelectedFlavors([]);
       setObservations('');
       setView('selection');
    }
  };

  const finalizeFlavorSelection = () => {
    if (selectedFlavors.length === 0) return;

    const price = flavorMode === 1 
      ? selectedFlavors[0].price 
      : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0);

    const newItem: OrderItem = {
      id: Math.random().toString(36).substr(2, 9),
      product1: selectedFlavors[0],
      product2: flavorMode === 2 ? selectedFlavors[1] : undefined,
      quantity: 1,
      observations: observations,
      totalPrice: price
    };

    setCart([...cart, newItem]);
    setView('menu');
    setSelectedFlavors([]);
    setObservations('');
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const totalCart = cart.reduce((acc, item) => acc + item.totalPrice, 0);

  const handleSendOrder = () => {
    if (!customer.name || !customer.address || !customer.phone) {
      alert("Por favor, preencha todos os campos do checkout!");
      return;
    }

    const orderNumber = Math.floor(1000 + Math.random() * 9000).toString();
    const orderDate = new Date().toLocaleString('pt-BR');

    let message = `*Már's Pizzaria - Pedido #${orderNumber}*\n\n`;
    message += `👤 *Cliente:* ${customer.name}\n`;
    message += `📞 *Telefone:* ${customer.phone}\n`;
    message += `📍 *Endereço:* ${customer.address}\n\n`;
    message += `🍕 *Itens:* \n`;

    cart.forEach((item, index) => {
      if (item.product2) {
        message += `${index + 1}. Meio ${item.product1.name} / Meio ${item.product2.name}`;
      } else {
        message += `${index + 1}. ${item.product1.name}`;
      }
      message += ` - R$ ${item.totalPrice.toFixed(2).replace('.', ',')}\n`;
      if (item.observations) message += `   _Obs: ${item.observations}_\n`;
    });

    message += `\n💰 *Total:* R$ ${totalCart.toFixed(2).replace('.', ',')}\n\n`;
    message += `Obrigado pela preferência!`;

    const history: OrderHistory = {
      orderNumber,
      items: cart,
      customer,
      date: orderDate
    };
    localStorage.setItem('marys_pizzaria_history', JSON.stringify(history));

    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/${PIZZARIA_CONFIG.whatsapp}?text=${encodedMessage}`, '_blank');
  };

  const repeatLastOrder = () => {
    if (lastOrder) {
      setCart(lastOrder.items);
      setCustomer(lastOrder.customer);
      setView('menu');
    }
  };

  return (
    <div className="min-h-screen pb-24 max-w-md mx-auto relative bg-[#0f0f0f]">
      {/* Header */}
      <header className="pt-8 pb-4 px-6 text-center">
        <img src={PIZZARIA_CONFIG.logoUrl} alt="Logo" className="w-48 mx-auto mb-4" />
        <p className="text-yellow-500 text-sm font-semibold tracking-wide uppercase">{PIZZARIA_CONFIG.address}</p>
        <p className="text-zinc-400 text-lg font-bold mt-1">{PIZZARIA_CONFIG.phone}</p>
      </header>

      {/* Hero */}
      {view === 'menu' && (
        <div className="px-6 mb-8">
          <div className="relative rounded-2xl overflow-hidden h-48 shadow-2xl">
            <img 
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&q=80&w=800" 
              className="w-full h-full object-cover" 
              alt="Pizza Banner"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end p-6">
              <h2 className="text-2xl font-bold text-white">Peça Online Agora</h2>
            </div>
          </div>
        </div>
      )}

      {/* Navigation / History Prompt */}
      {lastOrder && view === 'menu' && cart.length === 0 && (
        <div className="mx-6 mb-6 p-4 bg-orange-600/20 border border-orange-600/50 rounded-xl flex items-center justify-between">
          <span className="text-sm text-orange-200">Deseja repetir o último pedido?</span>
          <button 
            onClick={repeatLastOrder}
            className="bg-orange-600 px-3 py-1 rounded-lg text-xs font-bold"
          >
            Repetir
          </button>
        </div>
      )}

      {/* Views */}
      <main className="px-6">
        {view === 'menu' && (
          <div className="space-y-10">
            {/* Pizzas */}
            <section>
              <h2 className="text-xl font-bold mb-4 border-l-4 border-orange-600 pl-3">Nossas Pizzas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_PIZZAS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            {/* Combos */}
            <section>
              <h2 className="text-xl font-bold mb-4 border-l-4 border-yellow-500 pl-3">Combos Especiais</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_COMBOS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            {/* Beverages */}
            <section>
              <h2 className="text-xl font-bold mb-4 border-l-4 border-white pl-3">Bebidas Geladas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_BEVERAGES.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'selection' && (
          <div className="fixed inset-0 z-50 bg-[#0f0f0f] p-6 overflow-y-auto">
             <div className="flex items-center justify-between mb-8">
               <h2 className="text-2xl font-bold text-orange-500">Personalize sua Pizza</h2>
               <button onClick={() => setView('menu')} className="text-zinc-500">Voltar</button>
             </div>

             {/* Mode Selector */}
             <div className="flex bg-zinc-900 p-1 rounded-xl mb-8">
               <button 
                 onClick={() => { setFlavorMode(1); setSelectedFlavors(prev => prev.slice(0, 1)); }}
                 className={`flex-1 py-3 rounded-lg font-bold transition-all ${flavorMode === 1 ? 'bg-orange-600 text-white shadow-lg' : 'text-zinc-400'}`}
               >
                 1 Sabor
               </button>
               <button 
                 onClick={() => setFlavorMode(2)}
                 className={`flex-1 py-3 rounded-lg font-bold transition-all ${flavorMode === 2 ? 'bg-orange-600 text-white shadow-lg' : 'text-zinc-400'}`}
               >
                 2 Sabores (Meio a Meio)
               </button>
             </div>

             {/* Pizza Visual Representation */}
             <div className="relative w-64 h-64 mx-auto mb-10 group">
                <div className="absolute inset-0 border-8 border-orange-900 rounded-full shadow-[0_0_30px_rgba(234,88,12,0.3)]"></div>
                {flavorMode === 1 ? (
                  <div className="w-full h-full rounded-full overflow-hidden">
                    {selectedFlavors[0] ? (
                      <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover animate-in fade-in zoom-in duration-300" />
                    ) : (
                      <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-zinc-600 text-sm p-8 text-center">Escolha o sabor abaixo</div>
                    )}
                  </div>
                ) : (
                  <div className="w-full h-full rounded-full overflow-hidden flex">
                    <div className="w-1/2 h-full border-r-2 border-orange-900">
                      {selectedFlavors[0] ? (
                        <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover animate-in slide-in-from-left duration-300" />
                      ) : (
                        <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-[10px] p-2 text-center text-zinc-600">Sabor 1</div>
                      )}
                    </div>
                    <div className="w-1/2 h-full">
                      {selectedFlavors[1] ? (
                        <img src={selectedFlavors[1].imageUrl} className="w-full h-full object-cover animate-in slide-in-from-right duration-300" />
                      ) : (
                        <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-[10px] p-2 text-center text-zinc-600">Sabor 2</div>
                      )}
                    </div>
                  </div>
                )}

                {/* Remove buttons for visual board */}
                {selectedFlavors.length > 0 && (
                  <div className="absolute -top-2 -right-2">
                    <button 
                      onClick={() => setSelectedFlavors([])}
                      className="bg-red-600 w-8 h-8 rounded-full flex items-center justify-center shadow-lg border-2 border-white"
                    >
                      ✕
                    </button>
                  </div>
                )}
             </div>

             {/* Price Badge */}
             {selectedFlavors.length > 0 && (
                <div className="text-center mb-6">
                   <div className="inline-block px-4 py-2 bg-yellow-500 text-black font-black text-lg rounded-full shadow-lg">
                      R$ {(flavorMode === 1 
                        ? selectedFlavors[0].price 
                        : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0)
                      ).toFixed(2).replace('.', ',')}
                   </div>
                   {flavorMode === 2 && selectedFlavors.length === 2 && (
                     <p className="text-[10px] text-zinc-500 mt-2 uppercase tracking-widest">*Preço baseado no sabor mais caro</p>
                   )}
                </div>
             )}

             {/* Flavor List */}
             <div className="space-y-4">
               <h3 className="text-zinc-400 font-bold uppercase text-xs tracking-widest">Selecione {flavorMode === 2 ? 'os sabores' : 'o sabor'}:</h3>
               <div className="grid grid-cols-1 gap-3 pb-10">
                 {MENU_PIZZAS.map(p => {
                   const isSelected = selectedFlavors.find(f => f.id === p.id);
                   const isFull = flavorMode === 1 ? selectedFlavors.length >= 1 : selectedFlavors.length >= 2;

                   return (
                    <button
                      key={p.id}
                      disabled={isFull && !isSelected}
                      onClick={() => {
                        if (isSelected) {
                          setSelectedFlavors(prev => prev.filter(f => f.id !== p.id));
                        } else {
                          setSelectedFlavors(prev => [...prev, p]);
                        }
                      }}
                      className={`flex items-center p-3 rounded-xl border transition-all ${
                        isSelected 
                        ? 'bg-orange-600/20 border-orange-600' 
                        : (isFull && !isSelected) ? 'opacity-30 border-zinc-800' : 'bg-zinc-900 border-zinc-800 active:scale-95'
                      }`}
                    >
                      <img src={p.imageUrl} className="w-12 h-12 rounded-lg object-cover mr-4" />
                      <div className="text-left flex-1">
                        <div className="font-bold text-sm">{p.name}</div>
                        <div className="text-xs text-zinc-500">R$ {p.price.toFixed(2).replace('.', ',')}</div>
                      </div>
                      {isSelected && <span className="text-orange-500 font-bold">✓</span>}
                    </button>
                   );
                 })}
               </div>
             </div>

             <div className="sticky bottom-6 mt-8 space-y-4 bg-black p-4 rounded-2xl shadow-2xl">
               <textarea 
                  placeholder="Observações (ex: Sem cebola, massa fina...)"
                  value={observations}
                  onChange={(e) => setObservations(e.target.value)}
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-sm focus:outline-none focus:ring-1 focus:ring-orange-500"
                  rows={2}
               />
               <button 
                 disabled={(flavorMode === 1 && selectedFlavors.length === 0) || (flavorMode === 2 && selectedFlavors.length < 2)}
                 onClick={finalizeFlavorSelection}
                 className="w-full bg-orange-600 disabled:bg-zinc-800 disabled:text-zinc-600 text-white font-black py-4 rounded-xl shadow-[0_10px_20px_-10px_rgba(234,88,12,0.5)] uppercase"
               >
                 Confirmar Pizza
               </button>
             </div>
          </div>
        )}

        {view === 'checkout' && (
          <div className="space-y-8 animate-in slide-in-from-bottom duration-300">
            <div className="flex items-center justify-between">
               <h2 className="text-2xl font-bold text-orange-500">Checkout</h2>
               <button onClick={() => setView('menu')} className="text-zinc-500">Voltar</button>
            </div>

            {/* Summary */}
            <div className="bg-zinc-900 rounded-2xl p-6 border border-zinc-800 shadow-xl">
              <h3 className="text-zinc-400 font-bold uppercase text-xs tracking-widest mb-4">Seu Pedido</h3>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex justify-between border-b border-zinc-800 pb-3">
                    <div className="flex-1 pr-4">
                      <div className="font-bold text-white">
                        {item.product2 ? `Meio ${item.product1.name} / Meio ${item.product2.name}` : item.product1.name}
                      </div>
                      {item.observations && <div className="text-[10px] text-zinc-500 mt-1 italic">Obs: {item.observations}</div>}
                    </div>
                    <div className="text-yellow-400 font-bold">R$ {item.totalPrice.toFixed(2).replace('.', ',')}</div>
                    <button onClick={() => removeFromCart(item.id)} className="ml-4 text-red-500 font-bold">✕</button>
                  </div>
                ))}
                <div className="flex justify-between pt-2 text-xl font-black text-orange-500 uppercase tracking-tight">
                  <span>Total</span>
                  <span>R$ {totalCart.toFixed(2).replace('.', ',')}</span>
                </div>
              </div>
            </div>

            {/* Customer Form */}
            <div className="space-y-4">
               <h3 className="text-zinc-400 font-bold uppercase text-xs tracking-widest">Informações de Entrega</h3>
               <input 
                 type="text" 
                 placeholder="Nome Completo" 
                 value={customer.name}
                 onChange={(e) => setCustomer({...customer, name: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-500"
               />
               <input 
                 type="tel" 
                 placeholder="Telefone (WhatsApp)" 
                 value={customer.phone}
                 onChange={(e) => setCustomer({...customer, phone: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-500"
               />
               <textarea 
                 placeholder="Endereço Completo (Rua, Número, Bairro, Referência)" 
                 value={customer.address}
                 onChange={(e) => setCustomer({...customer, address: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-500"
                 rows={3}
               />
            </div>

            <button 
              onClick={handleSendOrder}
              className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-4 rounded-xl shadow-lg flex items-center justify-center space-x-3 uppercase tracking-wider"
            >
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.588-5.946 0-6.556 5.332-11.888 11.888-11.888 3.176 0 6.161 1.237 8.404 3.484 2.247 2.247 3.484 5.232 3.484 8.404 0 6.556-5.332 11.89-11.888 11.89-1.995 0-3.959-.502-5.706-1.454l-6.281 1.673zm6.333-3.454c1.559.926 3.097 1.416 4.61 1.416 5.426 0 9.838-4.412 9.838-9.838 0-2.628-1.023-5.099-2.882-6.958s-4.33-2.882-6.956-2.882c-5.426 0-9.838 4.412-9.838 9.838 0 1.83.513 3.618 1.482 5.176l-1.002 3.662 3.748-.996zm11.367-6.384c-.286-.143-1.693-.835-1.954-.93-.262-.095-.453-.143-.643.143s-.738.93-.905 1.12c-.167.19-.333.214-.619.071-.286-.143-1.208-.445-2.3-1.419-.848-.756-1.42-1.689-1.586-1.975-.167-.286-.018-.441.125-.582.129-.127.286-.333.429-.5.143-.167.19-.286.286-.476.095-.19.048-.357-.024-.5-.071-.143-.643-1.548-.881-2.12-.232-.556-.466-.481-.643-.49-.166-.008-.357-.01-.548-.01s-.5.071-.762.357c-.262.286-1.001.977-1.001 2.382s1.024 2.763 1.167 2.953c.143.19 2.015 3.078 4.881 4.319.681.295 1.214.471 1.629.603.684.217 1.307.187 1.8.113.55-.082 1.693-.691 1.93-.1.357-.238.405-.238.405s-.286.071-.429.214-.286.143-.571.071z"/></svg>
              <span>Enviar para o WhatsApp</span>
            </button>
          </div>
        )}
      </main>

      {/* Persistent Call-to-Action (Cart) */}
      {view === 'menu' && cart.length > 0 && (
        <div className="fixed bottom-6 left-6 right-6 z-40 max-w-md mx-auto">
          <button 
            onClick={() => setView('checkout')}
            className="w-full bg-orange-600 hover:bg-orange-700 text-white p-4 rounded-2xl shadow-2xl flex items-center justify-between animate-in fade-in slide-in-from-bottom duration-500"
          >
            <div className="flex items-center">
              <span className="bg-white text-orange-600 font-black w-7 h-7 flex items-center justify-center rounded-full mr-3 text-sm">{cart.length}</span>
              <span className="font-bold tracking-wide uppercase text-sm">Ver Carrinho</span>
            </div>
            <span className="text-lg font-black">R$ {totalCart.toFixed(2).replace('.', ',')}</span>
          </button>
        </div>
      )}
    </div>
  );
}

