import React, { useState, useEffect } from 'react';
import { PIZZARIA_CONFIG, MENU_PIZZAS, MENU_COMBOS, MENU_BEVERAGES } from './constants';
import { Product, OrderItem, CustomerData, OrderHistory } from './types';

// Helper Components
const ProductCard: React.FC<{ 
  product: Product; 
  onSelect: (p: Product) => void 
}> = ({ product, onSelect }) => (
  <div 
    onClick={() => onSelect(product)}
    className="bg-zinc-900 rounded-xl overflow-hidden shadow-lg border border-zinc-800 transition-transform active:scale-95 cursor-pointer flex flex-col"
  >
    <img src={product.imageUrl} alt={product.name} className="h-40 w-full object-cover" />
    <div className="p-4 flex-1 flex flex-col justify-between">
      <div>
        <h3 className="text-lg font-bold text-orange-500">{product.name}</h3>
        {product.ingredients && <p className="text-xs text-zinc-400 mt-1 line-clamp-2">{product.ingredients}</p>}
      </div>
      <div className="mt-4 flex items-center justify-between">
        <span className="text-xl font-bold text-yellow-400">R$ {product.price.toFixed(2).replace('.', ',')}</span>
        <button className="bg-orange-600 hover:bg-orange-700 text-white px-3 py-1 rounded-full text-sm font-semibold">
          Adicionar
        </button>
      </div>
    </div>
  </div>
);

export default function App() {
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [view, setView] = useState<'menu' | 'selection' | 'checkout'>('menu');
  const [flavorMode, setFlavorMode] = useState<1 | 2>(1);
  const [selectedFlavors, setSelectedFlavors] = useState<Product[]>([]);
  const [observations, setObservations] = useState('');
  const [customer, setCustomer] = useState<CustomerData>({ name: '', phone: '', address: '' });
  const [lastOrder, setLastOrder] = useState<OrderHistory | null>(null);

  // Load history
  useEffect(() => {
    const history = localStorage.getItem('marys_pizzaria_history');
    if (history) {
      setLastOrder(JSON.parse(history));
    }
  }, []);

  const addToCart = (product: Product) => {
    if (product.category !== 'PIZZA') {
       const newItem: OrderItem = {
         id: Math.random().toString(36).substr(2, 9),
         product1: product,
         quantity: 1,
         observations: '',
         totalPrice: product.price
       };
       setCart([...cart, newItem]);
    } else {
       setFlavorMode(1);
       setSelectedFlavors([]);
       setObservations('');
       setView('selection');
    }
  };

  const finalizeFlavorSelection = () => {
    if (selectedFlavors.length === 0) return;

    const price = flavorMode === 1 
      ? selectedFlavors[0].price 
      : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0);

    const newItem: OrderItem = {
      id: Math.random().toString(36).substr(2, 9),
      product1: selectedFlavors[0],
      product2: flavorMode === 2 ? selectedFlavors[1] : undefined,
      quantity: 1,
      observations: observations,
      totalPrice: price
    };

    setCart([...cart, newItem]);
    setView('menu');
    setSelectedFlavors([]);
    setObservations('');
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const totalCart = cart.reduce((acc, item) => acc + item.totalPrice, 0);

  const handleSendOrder = () => {
    if (!customer.name || !customer.address || !customer.phone) {
      alert("Por favor, preencha todos os campos do checkout!");
      return;
    }

    const orderNumber = Math.floor(1000 + Math.random() * 9000).toString();
    const orderDate = new Date().toLocaleString('pt-BR');

    let message = `*Már's Pizzaria - Pedido #${orderNumber}*\n\n`;
    message += `👤 *Cliente:* ${customer.name}\n`;
    message += `📞 *Telefone:* ${customer.phone}\n`;
    message += `📍 *Endereço:* ${customer.address}\n\n`;
    message += `🍕 *Itens:* \n`;

    cart.forEach((item, index) => {
      if (item.product2) {
        message += `${index + 1}. Meio ${item.product1.name} / Meio ${item.product2.name}`;
      } else {
        message += `${index + 1}. ${item.product1.name}`;
      }
      message += ` - R$ ${item.totalPrice.toFixed(2).replace('.', ',')}\n`;
      if (item.observations) message += `   _Obs: ${item.observations}_\n`;
    });

    message += `\n💰 *Total:* R$ ${totalCart.toFixed(2).replace('.', ',')}\n\n`;
    message += `Obrigado pela preferência!`;

    const history: OrderHistory = {
      orderNumber,
      items: cart,
      customer,
      date: orderDate
    };
    localStorage.setItem('marys_pizzaria_history', JSON.stringify(history));

    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/${PIZZARIA_CONFIG.whatsapp}?text=${encodedMessage}`, '_blank');
  };

  const repeatLastOrder = () => {
    if (lastOrder) {
      setCart(lastOrder.items);
      setCustomer(lastOrder.customer);
      setView('menu');
    }
  };

  return (
    <div className="min-h-screen pb-24 max-w-md mx-auto relative bg-[#0f0f0f]">
      {/* Header exactly as the screenshot */}
      <header className="pt-10 pb-6 px-6 text-center">
        <div className="mb-6">
           <img 
             src={PIZZARIA_CONFIG.logoUrl} 
             alt="Mary's Pizzaria Logo" 
             className="w-40 h-40 object-contain mx-auto"
             onError={(e) => {
               // Fallback if the requested file doesn't exist yet
               (e.target as HTMLImageElement).src = "https://images2.imgbox.com/39/1b/K8S9hP0H_o.png";
             }}
           />
        </div>
        <p className="text-yellow-500 text-[10px] font-bold tracking-widest uppercase mb-1">
          {PIZZARIA_CONFIG.address}
        </p>
        <p className="text-zinc-400 text-lg font-bold">
          {PIZZARIA_CONFIG.phone}
        </p>
      </header>

      {/* Hero Banner */}
      {view === 'menu' && (
        <div className="px-6 mb-10">
          <div className="relative rounded-2xl overflow-hidden h-52 shadow-2xl group cursor-pointer border border-zinc-800">
            <img 
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&q=80&w=800" 
              className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" 
              alt="Pizza Atraente"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent flex items-end p-6">
              <div className="animate-in slide-in-from-left duration-500">
                <h2 className="text-3xl font-black text-white uppercase italic tracking-tighter">Peça Online Agora</h2>
                <div className="h-1 w-20 bg-orange-600 mt-1"></div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Repeat Last Order UI */}
      {lastOrder && view === 'menu' && cart.length === 0 && (
        <div className="mx-6 mb-8 p-4 bg-orange-600/10 border border-orange-600/30 rounded-2xl flex items-center justify-between backdrop-blur-sm">
          <div className="flex flex-col">
            <span className="text-xs font-bold text-orange-200 uppercase tracking-wide">Bem-vindo de volta!</span>
            <span className="text-[10px] text-zinc-500">Deseja repetir o último pedido?</span>
          </div>
          <button 
            onClick={repeatLastOrder}
            className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-xl text-xs font-black uppercase transition-all shadow-lg active:scale-95"
          >
            Repetir
          </button>
        </div>
      )}

      {/* Main Content Views */}
      <main className="px-6">
        {view === 'menu' && (
          <div className="space-y-12">
            <section>
              <h2 className="text-lg font-black mb-6 border-l-4 border-orange-600 pl-3 uppercase tracking-tighter italic">Pizzas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_PIZZAS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            <section>
              <h2 className="text-lg font-black mb-6 border-l-4 border-yellow-500 pl-3 uppercase tracking-tighter italic">Combos</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_COMBOS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            <section>
              <h2 className="text-lg font-black mb-6 border-l-4 border-white pl-3 uppercase tracking-tighter italic">Bebidas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_BEVERAGES.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'selection' && (
          <div className="fixed inset-0 z-50 bg-[#0f0f0f] p-6 overflow-y-auto">
             <div className="flex items-center justify-between mb-8">
               <h2 className="text-2xl font-black text-orange-500 uppercase italic tracking-tighter">Personalizar</h2>
               <button onClick={() => setView('menu')} className="bg-zinc-900 p-2 rounded-full w-10 h-10 flex items-center justify-center text-zinc-400 font-bold border border-zinc-800">✕</button>
             </div>

             <div className="flex bg-zinc-900 p-1.5 rounded-2xl mb-10 shadow-inner border border-zinc-800">
               <button 
                 onClick={() => { setFlavorMode(1); setSelectedFlavors(prev => prev.slice(0, 1)); }}
                 className={`flex-1 py-4 rounded-xl font-black text-xs uppercase transition-all ${flavorMode === 1 ? 'bg-orange-600 text-white shadow-[0_5px_15px_-5px_rgba(234,88,12,1)]' : 'text-zinc-500'}`}
               >
                 1 Sabor
               </button>
               <button 
                 onClick={() => setFlavorMode(2)}
                 className={`flex-1 py-4 rounded-xl font-black text-xs uppercase transition-all ${flavorMode === 2 ? 'bg-orange-600 text-white shadow-[0_5px_15px_-5px_rgba(234,88,12,1)]' : 'text-zinc-500'}`}
               >
                 2 Sabores
               </button>
             </div>

             <div className="relative w-64 h-64 mx-auto mb-10">
                <div className="absolute inset-0 border-[10px] border-orange-950/50 rounded-full shadow-[0_0_50px_rgba(234,88,12,0.2)]"></div>
                {flavorMode === 1 ? (
                  <div className="w-full h-full rounded-full overflow-hidden p-1 bg-zinc-900">
                    {selectedFlavors[0] ? (
                      <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover animate-in fade-in zoom-in duration-500 rounded-full" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-zinc-600 text-[10px] p-10 text-center uppercase font-black">Selecione o sabor</div>
                    )}
                  </div>
                ) : (
                  <div className="w-full h-full rounded-full overflow-hidden flex p-1 bg-zinc-900">
                    <div className="w-1/2 h-full border-r-2 border-orange-950/50 relative">
                      {selectedFlavors[0] ? (
                        <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover animate-in slide-in-from-left duration-500" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-[8px] p-2 text-center text-zinc-600 uppercase font-black">Sabor 1</div>
                      )}
                    </div>
                    <div className="w-1/2 h-full relative">
                      {selectedFlavors[1] ? (
                        <img src={selectedFlavors[1].imageUrl} className="w-full h-full object-cover animate-in slide-in-from-right duration-500" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-[8px] p-2 text-center text-zinc-600 uppercase font-black">Sabor 2</div>
                      )}
                    </div>
                  </div>
                )}

                {selectedFlavors.length > 0 && (
                  <button 
                    onClick={() => setSelectedFlavors([])}
                    className="absolute -top-2 -right-2 bg-red-600 text-white w-10 h-10 rounded-full flex items-center justify-center shadow-2xl border-2 border-[#0f0f0f] active:scale-90 transition-transform font-bold"
                  >
                    ✕
                  </button>
                )}
             </div>

             {selectedFlavors.length > 0 && (
                <div className="text-center mb-8">
                   <div className="inline-block px-6 py-2.5 bg-yellow-500 text-black font-black text-xl rounded-full shadow-[0_10px_20px_-5px_rgba(250,204,21,0.5)]">
                      R$ {(flavorMode === 1 
                        ? selectedFlavors[0].price 
                        : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0)
                      ).toFixed(2).replace('.', ',')}
                   </div>
                   {flavorMode === 2 && selectedFlavors.length === 2 && (
                     <p className="text-[9px] text-zinc-500 mt-3 uppercase tracking-[0.2em] font-bold">*Preço do sabor mais caro</p>
                   )}
                </div>
             )}

             <div className="space-y-4 mb-32">
               <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest pl-1">Opções Disponíveis:</h3>
               <div className="grid grid-cols-1 gap-3">
                 {MENU_PIZZAS.map(p => {
                   const isSelected = selectedFlavors.find(f => f.id === p.id);
                   const isFull = flavorMode === 1 ? selectedFlavors.length >= 1 : selectedFlavors.length >= 2;

                   return (
                    <button
                      key={p.id}
                      disabled={isFull && !isSelected}
                      onClick={() => {
                        if (isSelected) {
                          setSelectedFlavors(prev => prev.filter(f => f.id !== p.id));
                        } else {
                          setSelectedFlavors(prev => [...prev, p]);
                        }
                      }}
                      className={`flex items-center p-3 rounded-2xl border transition-all active:scale-[0.98] ${
                        isSelected 
                        ? 'bg-orange-600/20 border-orange-600' 
                        : (isFull && !isSelected) ? 'opacity-20 border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/50 border-zinc-800'
                      }`}
                    >
                      <img src={p.imageUrl} className="w-14 h-14 rounded-xl object-cover mr-4 shadow-lg" />
                      <div className="text-left flex-1">
                        <div className="font-black text-sm uppercase tracking-tighter">{p.name}</div>
                        <div className="text-[10px] text-yellow-500 font-bold">R$ {p.price.toFixed(2).replace('.', ',')}</div>
                      </div>
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-orange-600 border-orange-600 text-white' : 'border-zinc-700'}`}>
                        {isSelected && <span className="text-[10px] font-black">✓</span>}
                      </div>
                    </button>
                   );
                 })}
               </div>
             </div>

             <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black to-transparent">
               <div className="max-w-md mx-auto space-y-4">
                 <textarea 
                    placeholder="Deseja remover algo? Alguma observação especial?"
                    value={observations}
                    onChange={(e) => setObservations(e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-2xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-orange-600 placeholder:text-zinc-600 text-white"
                    rows={2}
                 />
                 <button 
                   disabled={(flavorMode === 1 && selectedFlavors.length === 0) || (flavorMode === 2 && selectedFlavors.length < 2)}
                   onClick={finalizeFlavorSelection}
                   className="w-full bg-orange-600 disabled:bg-zinc-800 disabled:text-zinc-600 text-white font-black py-5 rounded-2xl shadow-2xl uppercase tracking-widest text-sm active:scale-95 transition-all"
                 >
                   Adicionar ao Carrinho
                 </button>
               </div>
             </div>
          </div>
        )}

        {view === 'checkout' && (
          <div className="space-y-10 animate-in slide-in-from-bottom duration-500">
            <div className="flex items-center justify-between">
               <h2 className="text-2xl font-black text-orange-500 uppercase italic tracking-tighter">Checkout</h2>
               <button onClick={() => setView('menu')} className="bg-zinc-900 p-2 rounded-full w-10 h-10 flex items-center justify-center text-zinc-400 font-bold border border-zinc-800">✕</button>
            </div>

            <div className="bg-zinc-900 rounded-3xl p-6 border border-zinc-800 shadow-2xl">
              <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest mb-6 border-b border-zinc-800 pb-2">Seu Pedido</h3>
              <div className="space-y-6">
                {cart.map(item => (
                  <div key={item.id} className="flex justify-between items-start">
                    <div className="flex-1 pr-4">
                      <div className="font-black text-white uppercase text-sm leading-tight">
                        {item.product2 ? `1/2 ${item.product1.name}\n1/2 ${item.product2.name}` : item.product1.name}
                      </div>
                      {item.observations && <div className="text-[10px] text-zinc-500 mt-2 bg-black/30 p-2 rounded-lg border border-zinc-800 italic">Obs: {item.observations}</div>}
                    </div>
                    <div className="flex flex-col items-end">
                      <div className="text-yellow-400 font-black text-sm mb-2">R$ {item.totalPrice.toFixed(2).replace('.', ',')}</div>
                      <button onClick={() => removeFromCart(item.id)} className="bg-red-950/30 text-red-500 p-2 rounded-lg active:scale-90 transition-transform">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </div>
                  </div>
                ))}

                <div className="pt-6 border-t border-zinc-800">
                  <div className="flex justify-between items-center text-2xl font-black text-orange-500 uppercase tracking-tighter">
                    <span>Total</span>
                    <span>R$ {totalCart.toFixed(2).replace('.', ',')}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-4">
               <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest pl-1">Dados de Entrega:</h3>
               <div className="space-y-3">
                 <input 
                   type="text" 
                   placeholder="Qual seu nome?" 
                   value={customer.name}
                   onChange={(e) => setCustomer({...customer, name: e.target.value})}
                   className="w-full bg-zinc-900/50 border border-zinc-800 rounded-2xl p-5 focus:outline-none focus:ring-2 focus:ring-orange-600 placeholder:text-zinc-600"
                 />
                 <input 
                   type="tel" 
                   placeholder="WhatsApp para contato" 
                   value={customer.phone}
                   onChange={(e) => setCustomer({...customer, phone: e.target.value})}
                   className="w-full bg-zinc-900/50 border border-zinc-800 rounded-2xl p-5 focus:outline-none focus:ring-2 focus:ring-orange-600 placeholder:text-zinc-600"
                 />
                 <textarea 
                   placeholder="Onde devemos entregar? (Endereço completo)" 
                   value={customer.address}
                   onChange={(e) => setCustomer({...customer, address: e.target.value})}
                   className="w-full bg-zinc-900/50 border border-zinc-800 rounded-2xl p-5 focus:outline-none focus:ring-2 focus:ring-orange-600 placeholder:text-zinc-600 min-h-[120px]"
                 />
               </div>
            </div>

            <button 
              onClick={handleSendOrder}
              className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-6 rounded-3xl shadow-[0_15px_30px_-10px_rgba(22,163,74,0.5)] flex items-center justify-center space-x-4 uppercase tracking-widest text-sm transition-all active:scale-95 mb-10"
            >
              <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.588-5.946 0-6.556 5.332-11.888 11.888-11.888 3.176 0 6.161 1.237 8.404 3.484 2.247 2.247 3.484 5.232 3.484 8.404 0 6.556-5.332 11.89-11.888 11.89-1.995 0-3.959-.502-5.706-1.454l-6.281 1.673zm6.333-3.454c1.559.926 3.097 1.416 4.61 1.416 5.426 0 9.838-4.412 9.838-9.838 0-2.628-1.023-5.099-2.882-6.958s-4.33-2.882-6.956-2.882c-5.426 0-9.838 4.412-9.838 9.838 0 1.83.513 3.618 1.482 5.176l-1.002 3.662 3.748-.996zm11.367-6.384c-.286-.143-1.693-.835-1.954-.93-.262-.095-.453-.143-.643.143s-.738.93-.905 1.12c-.167.19-.333.214-.619.071-.286-.143-1.208-.445-2.3-1.419-.848-.756-1.42-1.689-1.586-1.975-.167-.286-.018-.441.125-.582.129-.127.286-.333.429-.5.143-.167.19-.286.286-.476.095-.19.048-.357-.024-.5-.071-.143-.643-1.548-.881-2.12-.232-.556-.466-.481-.643-.49-.166-.008-.357-.01-.548-.01s-.5.071-.762.357c-.262.286-1.001.977-1.001 2.382s1.024 2.763 1.167 2.953c.143.19 2.015 3.078 4.881 4.319.681.295 1.214.471 1.629.603.684.217 1.307.187 1.8.113.55-.082 1.693-.691 1.93-.1.357-.238.405-.238.405s-.286.071-.429.214-.286.143-.571.071z"/></svg>
              <span>Finalizar Pedido</span>
            </button>
          </div>
        )}
      </main>

      {/* Floating Cart Button */}
      {view === 'menu' && cart.length > 0 && (
        <div className="fixed bottom-10 left-6 right-6 z-40 max-w-md mx-auto">
          <button 
            onClick={() => setView('checkout')}
            className="w-full bg-orange-600 hover:bg-orange-700 text-white p-5 rounded-3xl shadow-[0_20px_40px_-10px_rgba(234,88,12,0.6)] flex items-center justify-between animate-in fade-in slide-in-from-bottom duration-500 active:scale-95 transition-all"
          >
            <div className="flex items-center">
              <div className="bg-white text-orange-600 font-black w-8 h-8 flex items-center justify-center rounded-xl mr-4 shadow-lg">
                {cart.length}
              </div>
              <span className="font-black tracking-widest uppercase text-xs">Ver Carrinho</span>
            </div>
            <div className="flex flex-col items-end">
              <span className="text-[10px] uppercase font-bold text-orange-200">Total</span>
              <span className="text-xl font-black">R$ {totalCart.toFixed(2).replace('.', ',')}</span>
            </div>
          </button>
        </div>
      )}
    </div>
  );
}

