import React, { useState, useMemo } from 'react';
import { PIZZARIA_CONFIG, MENU_PIZZAS, MENU_COMBOS, MENU_BEVERAGES } from './constants';
import { Product, OrderItem, Category } from './types';

// ProductCard displays a single product with its details and selection action
const ProductCard: React.FC<{ 
  product: Product; 
  onSelect: (p: Product) => void 
}> = ({ product, onSelect }) => (
  <div 
    onClick={() => onSelect(product)}
    className="bg-zinc-900 rounded-2xl overflow-hidden shadow-lg border border-zinc-800 transition-transform active:scale-95 cursor-pointer flex flex-col group"
  >
    <div className="relative h-44 overflow-hidden">
      <img src={product.imageUrl} alt={product.name} className="h-full w-full object-cover group-hover:scale-105 transition-transform duration-500" />
      <div className="absolute top-2 right-2 bg-black/60 backdrop-blur-md px-2 py-1 rounded-lg text-yellow-400 font-bold text-sm">
        R$ {product.price.toFixed(2).replace('.', ',')}
      </div>
    </div>
    <div className="p-4 flex-1 flex flex-col justify-between">
      <div>
        <h3 className="text-lg font-bold text-orange-500 uppercase tracking-tight">{product.name}</h3>
        {product.ingredients && <p className="text-[10px] text-zinc-400 mt-1 line-clamp-2 leading-relaxed">{product.ingredients}</p>}
      </div>
      <button className="mt-4 w-full bg-orange-600 hover:bg-orange-700 text-white py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-colors">
        Escolher
      </button>
    </div>
  </div>
);

/**
 * Main Application Component
 * Manages the store front, product navigation, shopping cart, and order generation.
 */
export default function App() {
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [view, setView] = useState<'menu' | 'selection' | 'checkout'>('menu');
  const [activeCategory, setActiveCategory] = useState<Category>('PIZZA');

  // Selection logic for Pizzas (Single flavor vs Half-and-Half)
  const [flavorMode, setFlavorMode] = useState<1 | 2>(1); 
  const [tempSelection, setTempSelection] = useState<Product[]>([]);
  const [observations, setObservations] = useState('');

  // Derived state for products currently visible
  const products = useMemo(() => {
    if (activeCategory === 'PIZZA') return MENU_PIZZAS;
    if (activeCategory === 'COMBO') return MENU_COMBOS;
    return MENU_BEVERAGES;
  }, [activeCategory]);

  const handleProductClick = (product: Product) => {
    if (product.category !== 'PIZZA') {
      const newItem: OrderItem = {
        id: Math.random().toString(36).substring(2, 9),
        product1: product,
        quantity: 1,
        observations: '',
        totalPrice: product.price
      };
      setCart(prev => [...prev, newItem]);
    } else {
      setTempSelection([product]);
      setFlavorMode(1);
      setView('selection');
    }
  };

  const addToCart = () => {
    if (tempSelection.length === 0) return;

    let totalPrice = 0;
    if (flavorMode === 1) {
      totalPrice = tempSelection[0].price;
    } else {
      // For half-and-half, charge the price of the more expensive flavor
      totalPrice = Math.max(tempSelection[0].price, tempSelection[1]?.price || 0);
    }

    const newItem: OrderItem = {
      id: Math.random().toString(36).substring(2, 9),
      product1: tempSelection[0],
      product2: flavorMode === 2 ? tempSelection[1] : undefined,
      quantity: 1,
      observations: observations,
      totalPrice: totalPrice
    };

    setCart(prev => [...prev, newItem]);
    setView('menu');
    setTempSelection([]);
    setObservations('');
  };

  const totalCart = cart.reduce((acc, item) => acc + item.totalPrice, 0);

  const formatWhatsAppMessage = () => {
    let message = `*🍕 Novo Pedido - ${PIZZARIA_CONFIG.name}*\n\n`;
    cart.forEach((item, index) => {
      message += `*${index + 1}.* ${item.product1.name}`;
      if (item.product2) message += ` / ${item.product2.name}`;
      message += ` - R$ ${item.totalPrice.toFixed(2).replace('.', ',')}\n`;
      if (item.observations) message += `   _Obs: ${item.observations}_\n`;
    });
    message += `\n*Total: R$ ${totalCart.toFixed(2).replace('.', ',')}*\n\n📍 Endereço: _Favor informar o endereço de entrega_`;

    return `https://wa.me/${PIZZARIA_CONFIG.whatsapp}?text=${encodeURIComponent(message)}`;
  };

  // Selection view for configuring pizzas
  if (view === 'selection') {
    return (
      <div className="min-h-screen bg-black text-white p-6 font-sans">
        <div className="max-w-md mx-auto">
          <button onClick={() => setView('menu')} className="text-orange-500 mb-6 font-bold flex items-center gap-2 hover:opacity-80 transition-opacity">
             ← Voltar ao Menu
          </button>

          <h2 className="text-2xl font-black uppercase mb-4 text-orange-500 tracking-tighter italic">Personalizar Pizza</h2>

          <div className="flex gap-2 mb-6">
            <button 
              onClick={() => { setFlavorMode(1); setTempSelection([tempSelection[0]]); }}
              className={`flex-1 py-3 rounded-xl font-bold uppercase text-[10px] border-2 transition-all ${flavorMode === 1 ? 'bg-orange-600 border-orange-600 shadow-lg shadow-orange-600/20' : 'border-zinc-800 text-zinc-500'}`}
            >
              Sabor Único
            </button>
            <button 
              onClick={() => setFlavorMode(2)}
              className={`flex-1 py-3 rounded-xl font-bold uppercase text-[10px] border-2 transition-all ${flavorMode === 2 ? 'bg-orange-600 border-orange-600 shadow-lg shadow-orange-600/20' : 'border-zinc-800 text-zinc-500'}`}
            >
              Meio a Meio
            </button>
          </div>

          <div className="space-y-4">
            <div className="p-4 bg-zinc-900 rounded-2xl border border-zinc-800">
              <span className="text-zinc-500 text-[9px] uppercase font-black tracking-widest">Sabor Primário</span>
              <p className="text-lg font-bold text-orange-500">{tempSelection[0].name}</p>
            </div>

            {flavorMode === 2 && (
              <div className="space-y-2">
                <span className="text-zinc-500 text-[9px] uppercase font-black tracking-widest">Escolha o Segundo Sabor</span>
                <div className="grid grid-cols-2 gap-2 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
                  {MENU_PIZZAS.map(p => (
                    <button 
                      key={p.id}
                      onClick={() => setTempSelection([tempSelection[0], p])}
                      className={`p-3 rounded-xl text-left border-2 transition-colors ${tempSelection[1]?.id === p.id ? 'border-orange-600 bg-orange-600/10' : 'border-zinc-800 bg-zinc-900'}`}
                    >
                      <p className="text-xs font-bold">{p.name}</p>
                      <p className="text-[10px] text-zinc-500">R$ {p.price.toFixed(2)}</p>
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="mt-4">
              <span className="text-zinc-500 text-[9px] uppercase font-black tracking-widest">Observações Adicionais</span>
              <textarea 
                value={observations}
                onChange={(e) => setObservations(e.target.value)}
                placeholder="Ex: Tirar cebola, adicionar borda recheada..."
                className="w-full mt-2 bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-sm focus:border-orange-600 outline-none h-24 resize-none transition-colors"
              />
            </div>

            <button 
              onClick={addToCart}
              disabled={flavorMode === 2 && !tempSelection[1]}
              className="w-full bg-orange-600 disabled:opacity-50 hover:bg-orange-700 text-white py-4 rounded-2xl font-black uppercase tracking-widest transition-all mt-4 shadow-xl shadow-orange-600/20"
            >
              Adicionar ao Pedido
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-orange-500/30">
      {/* Navigation Header */}
      <header className="sticky top-0 z-50 bg-black/90 backdrop-blur-xl border-b border-zinc-900 p-4">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-orange-600 rounded-xl flex items-center justify-center font-black text-2xl italic text-black -rotate-3">
              M
            </div>
            <div>
              <h1 className="text-xl font-black uppercase tracking-tighter leading-none italic">{PIZZARIA_CONFIG.name}</h1>
              <p className="text-[10px] text-zinc-500 uppercase tracking-widest mt-1 font-bold">Qualidade Premium</p>
            </div>
          </div>
          {cart.length > 0 && view === 'menu' && (
            <button 
              onClick={() => setView('checkout')}
              className="bg-yellow-400 text-black px-4 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2"
            >
              🛒 Carrinho ({cart.length})
            </button>
          )}
        </div>
      </header>

      <main className="max-w-5xl mx-auto p-4 pb-40">
        {view === 'menu' ? (
          <>
            {/* Horizontal Category Navigation */}
            <div className="flex gap-2 mb-8 overflow-x-auto pb-4 scrollbar-hide no-scrollbar">
              {(['PIZZA', 'COMBO', 'BEVERAGE'] as Category[]).map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-8 py-3 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all border-2 ${activeCategory === cat ? 'bg-orange-600 border-orange-600 text-white shadow-lg shadow-orange-600/20' : 'bg-zinc-900 text-zinc-500 border-zinc-800 hover:border-zinc-700'}`}
                >
                  {cat === 'PIZZA' ? '🍕 Pizzas' : cat === 'COMBO' ? '🍟 Combos' : '🥤 Bebidas'}
                </button>
              ))}
            </div>

            {/* Product Display Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.map(product => (
                <ProductCard key={product.id} product={product} onSelect={handleProductClick} />
              ))}
            </div>
          </>
        ) : (
          <div className="max-w-md mx-auto">
            <button onClick={() => setView('menu')} className="text-orange-500 mb-6 font-bold flex items-center gap-2 hover:translate-x-[-4px] transition-transform">
              ← Ver mais itens
            </button>
            <h2 className="text-3xl font-black uppercase mb-8 text-orange-500 italic tracking-tighter">Meu Carrinho</h2>

            <div className="space-y-4 mb-8">
              {cart.map((item) => (
                <div key={item.id} className="bg-zinc-900 border border-zinc-800 p-5 rounded-2xl flex justify-between items-start">
                  <div className="flex-1">
                    <h4 className="font-bold text-sm uppercase tracking-tight">
                      {item.product1.name} {item.product2 ? <span className="text-zinc-500">& {item.product2.name}</span> : ''}
                    </h4>
                    {item.observations && <p className="text-[10px] text-zinc-500 italic mt-2 bg-black/40 p-2 rounded-lg">"{item.observations}"</p>}
                    <div className="flex items-center gap-3 mt-3">
                      <span className="text-orange-500 text-sm font-black italic">R$ {item.totalPrice.toFixed(2).replace('.', ',')}</span>
                    </div>
                  </div>
                  <button 
                    onClick={() => setCart(prev => prev.filter(i => i.id !== item.id))}
                    className="ml-4 text-[9px] font-black uppercase text-zinc-600 hover:text-red-500 transition-colors bg-black px-3 py-1 rounded-full border border-zinc-800"
                  >
                    Remover
                  </button>
                </div>
              ))}

              {cart.length === 0 && (
                <div className="text-center py-24 bg-zinc-900/30 rounded-3xl border border-dashed border-zinc-800">
                  <p className="text-zinc-600 font-bold uppercase text-[10px] tracking-widest">Carrinho vazio por enquanto</p>
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="border-t border-zinc-900 pt-8 mt-12">
                <div className="flex justify-between items-center mb-8 bg-zinc-900 p-6 rounded-2xl border border-zinc-800 shadow-xl shadow-black/50">
                  <span className="text-zinc-500 font-black uppercase text-[10px] tracking-widest">Total Estimado</span>
                  <span className="text-3xl font-black text-orange-500 italic">R$ {totalCart.toFixed(2).replace('.', ',')}</span>
                </div>

                <a 
                  href={formatWhatsAppMessage()}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="block w-full bg-green-600 hover:bg-green-700 text-white text-center py-5 rounded-2xl font-black uppercase tracking-widest transition-all shadow-xl shadow-green-900/20 active:scale-95"
                >
                  Enviar para o WhatsApp 📲
                </a>
                <p className="text-center text-[9px] text-zinc-700 mt-6 uppercase font-bold tracking-widest">
                  {PIZZARIA_CONFIG.address}
                </p>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Bottom Navigation */}
      {view === 'menu' && cart.length > 0 && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 w-full max-w-sm px-6">
          <button 
            onClick={() => setView('checkout')}
            className="w-full bg-orange-600 hover:bg-orange-700 text-white py-5 rounded-2xl font-black uppercase text-sm flex items-center justify-between px-8 shadow-[0_25px_50px_rgba(234,88,12,0.4)] transition-all hover:scale-[1.02] active:scale-95"
          >
            <div className="flex items-center gap-3">
              <span className="bg-black/20 px-3 py-1 rounded-lg text-xs font-black">🛒 {cart.length}</span>
              <span>Conferir Pedido</span>
            </div>
            <span className="font-black italic">R$ {totalCart.toFixed(2).replace('.', ',')}</span>
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { PIZZARIA_CONFIG, MENU_PIZZAS, MENU_COMBOS, MENU_BEVERAGES } from './constants';
import { Product, OrderItem, CustomerData, OrderHistory } from './types';

// Componente de Cartão de Produto simplificado para a lista única
const ProductCard: React.FC<{ 
  product: Product; 
  onSelect: (p: Product) => void 
}> = ({ product, onSelect }) => (
  <div 
    onClick={() => onSelect(product)}
    className="bg-zinc-900 rounded-xl overflow-hidden shadow-lg border border-zinc-800 transition-transform active:scale-95 cursor-pointer flex flex-col"
  >
    <img src={product.imageUrl} alt={product.name} className="h-40 w-full object-cover" />
    <div className="p-4 flex-1 flex flex-col justify-between">
      <div>
        <h3 className="text-lg font-bold text-orange-500 uppercase tracking-tight">{product.name}</h3>
        {product.ingredients && <p className="text-[10px] text-zinc-400 mt-1 line-clamp-2">{product.ingredients}</p>}
      </div>
      <div className="mt-4 flex items-center justify-between">
        <span className="text-xl font-bold text-yellow-400">R$ {product.price.toFixed(2).replace('.', ',')}</span>
        <button className="bg-orange-600 hover:bg-orange-700 text-white px-3 py-1 rounded-full text-xs font-black uppercase">
          Adicionar
        </button>
      </div>
    </div>
  </div>
);

export default function App() {
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [view, setView] = useState<'menu' | 'selection' | 'checkout'>('menu');
  const [flavorMode, setFlavorMode] = useState<1 | 2>(1);
  const [selectedFlavors, setSelectedFlavors] = useState<Product[]>([]);
  const [observations, setObservations] = useState('');
  const [customer, setCustomer] = useState<CustomerData>({ name: '', phone: '', address: '' });
  const [lastOrder, setLastOrder] = useState<OrderHistory | null>(null);

  // Carrega histórico do localStorage
  useEffect(() => {
    const history = localStorage.getItem('marys_pizzaria_history');
    if (history) {
      setLastOrder(JSON.parse(history));
    }
  }, []);

  const addToCart = (product: Product) => {
    if (product.category !== 'PIZZA') {
       const newItem: OrderItem = {
         id: Math.random().toString(36).substr(2, 9),
         product1: product,
         quantity: 1,
         observations: '',
         totalPrice: product.price
       };
       setCart([...cart, newItem]);
    } else {
       setFlavorMode(1);
       setSelectedFlavors([product]);
       setObservations('');
       setView('selection');
    }
  };

  const finalizeFlavorSelection = () => {
    if (selectedFlavors.length === 0) return;

    const price = flavorMode === 1 
      ? selectedFlavors[0].price 
      : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0);

    const newItem: OrderItem = {
      id: Math.random().toString(36).substr(2, 9),
      product1: selectedFlavors[0],
      product2: flavorMode === 2 ? selectedFlavors[1] : undefined,
      quantity: 1,
      observations: observations,
      totalPrice: price
    };

    setCart([...cart, newItem]);
    setView('menu');
    setSelectedFlavors([]);
    setObservations('');
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const totalCart = cart.reduce((acc, item) => acc + item.totalPrice, 0);

  const handleSendOrder = () => {
    if (!customer.name || !customer.address || !customer.phone) {
      alert("Por favor, preencha todos os campos do checkout!");
      return;
    }

    const orderNumber = Math.floor(1000 + Math.random() * 9000).toString();
    const orderDate = new Date().toLocaleString('pt-BR');

    let message = `*Már's Pizzaria - Pedido #${orderNumber}*\n\n`;
    message += `👤 *Cliente:* ${customer.name}\n`;
    message += `📞 *Telefone:* ${customer.phone}\n`;
    message += `📍 *Endereço:* ${customer.address}\n\n`;
    message += `🍕 *Itens:* \n`;

    cart.forEach((item, index) => {
      if (item.product2) {
        message += `${index + 1}. Meio ${item.product1.name} / Meio ${item.product2.name}`;
      } else {
        message += `${index + 1}. ${item.product1.name}`;
      }
      message += ` - R$ ${item.totalPrice.toFixed(2).replace('.', ',')}\n`;
      if (item.observations) message += `   _Obs: ${item.observations}_\n`;
    });

    message += `\n💰 *Total:* R$ ${totalCart.toFixed(2).replace('.', ',')}\n\n`;
    message += `Obrigado pela preferência!`;

    const history: OrderHistory = {
      orderNumber,
      items: cart,
      customer,
      date: orderDate
    };
    localStorage.setItem('marys_pizzaria_history', JSON.stringify(history));

    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/${PIZZARIA_CONFIG.whatsapp}?text=${encodedMessage}`, '_blank');
  };

  const repeatLastOrder = () => {
    if (lastOrder) {
      setCart(lastOrder.items);
      setCustomer(lastOrder.customer);
      setView('menu');
    }
  };

  return (
    <div className="min-h-screen pb-24 max-w-md mx-auto relative bg-[#0f0f0f]">
      {/* Header com logo centralizado conforme solicitado */}
      <header className="pt-10 pb-6 px-6 text-center">
        <div className="mb-4">
           <img 
             src={PIZZARIA_CONFIG.logoUrl} 
             alt="Mary's Pizzaria Logo" 
             className="w-48 h-48 object-contain mx-auto"
           />
        </div>
        <p className="text-yellow-500 text-[10px] font-bold tracking-widest uppercase mb-1">
          {PIZZARIA_CONFIG.address}
        </p>
        <p className="text-zinc-400 text-lg font-bold">
          {PIZZARIA_CONFIG.phone}
        </p>
      </header>

      {/* Banner de Hero */}
      {view === 'menu' && (
        <div className="px-6 mb-8">
          <div className="relative rounded-2xl overflow-hidden h-48 shadow-2xl border border-zinc-800">
            <img 
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&q=80&w=800" 
              className="w-full h-full object-cover" 
              alt="Pizza Banner"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent flex items-end p-6">
              <h2 className="text-2xl font-black text-white uppercase italic tracking-tighter">Peça Online Agora</h2>
            </div>
          </div>
        </div>
      )}

      {/* Repetir Pedido */}
      {lastOrder && view === 'menu' && cart.length === 0 && (
        <div className="mx-6 mb-6 p-4 bg-orange-600/10 border border-orange-600/30 rounded-xl flex items-center justify-between">
          <span className="text-xs text-orange-200">Deseja repetir o último pedido?</span>
          <button 
            onClick={repeatLastOrder}
            className="bg-orange-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase"
          >
            Repetir
          </button>
        </div>
      )}

      <main className="px-6">
        {view === 'menu' && (
          <div className="space-y-10">
            {/* Seções em lista única */}
            <section>
              <h2 className="text-lg font-black mb-4 border-l-4 border-orange-600 pl-3 uppercase italic">Pizzas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_PIZZAS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            <section>
              <h2 className="text-lg font-black mb-4 border-l-4 border-yellow-500 pl-3 uppercase italic">Combos</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_COMBOS.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>

            <section>
              <h2 className="text-lg font-black mb-4 border-l-4 border-white pl-3 uppercase italic">Bebidas</h2>
              <div className="grid grid-cols-1 gap-6">
                {MENU_BEVERAGES.map(p => (
                  <ProductCard key={p.id} product={p} onSelect={addToCart} />
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'selection' && (
          <div className="fixed inset-0 z-50 bg-[#0f0f0f] p-6 overflow-y-auto">
             <div className="flex items-center justify-between mb-8">
               <h2 className="text-2xl font-black text-orange-500 uppercase italic">Personalizar</h2>
               <button onClick={() => setView('menu')} className="text-zinc-500 font-bold">Voltar</button>
             </div>

             <div className="flex bg-zinc-900 p-1 rounded-xl mb-8">
               <button 
                 onClick={() => { setFlavorMode(1); setSelectedFlavors(prev => prev.slice(0, 1)); }}
                 className={`flex-1 py-3 rounded-lg font-black text-[10px] uppercase transition-all ${flavorMode === 1 ? 'bg-orange-600 text-white' : 'text-zinc-500'}`}
               >
                 1 Sabor
               </button>
               <button 
                 onClick={() => setFlavorMode(2)}
                 className={`flex-1 py-3 rounded-lg font-black text-[10px] uppercase transition-all ${flavorMode === 2 ? 'bg-orange-600 text-white' : 'text-zinc-500'}`}
               >
                 2 Sabores
               </button>
             </div>

             <div className="relative w-64 h-64 mx-auto mb-10">
                <div className="absolute inset-0 border-8 border-orange-950 rounded-full"></div>
                {flavorMode === 1 ? (
                  <div className="w-full h-full rounded-full overflow-hidden">
                    {selectedFlavors[0] ? (
                      <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-zinc-600 text-[10px] p-8 text-center uppercase font-black">Escolha o sabor</div>
                    )}
                  </div>
                ) : (
                  <div className="w-full h-full rounded-full overflow-hidden flex">
                    <div className="w-1/2 h-full border-r-2 border-orange-950">
                      {selectedFlavors[0] ? (
                        <img src={selectedFlavors[0].imageUrl} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-[8px] p-2 text-center text-zinc-600 uppercase font-black">Sabor 1</div>
                      )}
                    </div>
                    <div className="w-1/2 h-full">
                      {selectedFlavors[1] ? (
                        <img src={selectedFlavors[1].imageUrl} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-[8px] p-2 text-center text-zinc-600 uppercase font-black">Sabor 2</div>
                      )}
                    </div>
                  </div>
                )}

                {selectedFlavors.length > 0 && (
                  <div className="absolute -top-2 -right-2">
                    <button 
                      onClick={() => setSelectedFlavors([])}
                      className="bg-red-600 text-white w-8 h-8 rounded-full flex items-center justify-center shadow-lg border-2 border-[#0f0f0f] font-bold"
                    >
                      ✕
                    </button>
                  </div>
                )}
             </div>

             {selectedFlavors.length > 0 && (
                <div className="text-center mb-6">
                   <div className="inline-block px-4 py-2 bg-yellow-500 text-black font-black text-lg rounded-full">
                      R$ {(flavorMode === 1 
                        ? selectedFlavors[0].price 
                        : Math.max(selectedFlavors[0].price, selectedFlavors[1]?.price || 0)
                      ).toFixed(2).replace('.', ',')}
                   </div>
                </div>
             )}

             <div className="space-y-4 mb-32">
               <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest">Opções:</h3>
               <div className="grid grid-cols-1 gap-3">
                 {MENU_PIZZAS.map(p => {
                   const isSelected = selectedFlavors.find(f => f.id === p.id);
                   const isFull = flavorMode === 1 ? selectedFlavors.length >= 1 : selectedFlavors.length >= 2;

                   return (
                    <button
                      key={p.id}
                      disabled={isFull && !isSelected}
                      onClick={() => {
                        if (isSelected) {
                          setSelectedFlavors(prev => prev.filter(f => f.id !== p.id));
                        } else {
                          setSelectedFlavors(prev => [...prev, p]);
                        }
                      }}
                      className={`flex items-center p-3 rounded-xl border transition-all ${
                        isSelected 
                        ? 'bg-orange-600/20 border-orange-600' 
                        : (isFull && !isSelected) ? 'opacity-30 border-zinc-900' : 'bg-zinc-900 border-zinc-800'
                      }`}
                    >
                      <img src={p.imageUrl} className="w-12 h-12 rounded-lg object-cover mr-4" />
                      <div className="text-left flex-1">
                        <div className="font-black text-xs uppercase tracking-tight">{p.name}</div>
                        <div className="text-[10px] text-zinc-500">R$ {p.price.toFixed(2).replace('.', ',')}</div>
                      </div>
                      {isSelected && <span className="text-orange-500 font-bold">✓</span>}
                    </button>
                   );
                 })}
               </div>
             </div>

             <div className="fixed bottom-0 left-0 right-0 p-6 bg-black">
               <div className="max-w-md mx-auto space-y-4">
                 <textarea 
                    placeholder="Observações (ex: Sem cebola...)"
                    value={observations}
                    onChange={(e) => setObservations(e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-sm focus:outline-none focus:ring-1 focus:ring-orange-600"
                    rows={2}
                 />
                 <button 
                   disabled={(flavorMode === 1 && selectedFlavors.length === 0) || (flavorMode === 2 && selectedFlavors.length < 2)}
                   onClick={finalizeFlavorSelection}
                   className="w-full bg-orange-600 disabled:bg-zinc-800 disabled:text-zinc-600 text-white font-black py-4 rounded-xl uppercase tracking-widest text-xs"
                 >
                   Confirmar Pizza
                 </button>
               </div>
             </div>
          </div>
        )}

        {view === 'checkout' && (
          <div className="space-y-10 animate-in slide-in-from-bottom duration-300">
            <div className="flex items-center justify-between">
               <h2 className="text-2xl font-black text-orange-500 uppercase italic">Checkout</h2>
               <button onClick={() => setView('menu')} className="text-zinc-500 font-bold">Voltar</button>
            </div>

            <div className="bg-zinc-900 rounded-2xl p-6 border border-zinc-800">
              <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest mb-4">Seu Pedido</h3>
              <div className="space-y-4">
                {cart.map(item => (
                  <div key={item.id} className="flex justify-between items-start border-b border-zinc-800 pb-3">
                    <div className="flex-1 pr-4">
                      <div className="font-black text-white uppercase text-xs">
                        {item.product2 ? `Meio ${item.product1.name} / Meio ${item.product2.name}` : item.product1.name}
                      </div>
                      {item.observations && <div className="text-[10px] text-zinc-500 mt-1 italic">Obs: {item.observations}</div>}
                    </div>
                    <div className="text-yellow-400 font-black text-sm pr-4">R$ {item.totalPrice.toFixed(2).replace('.', ',')}</div>
                    <button onClick={() => removeFromCart(item.id)} className="text-red-500 font-bold">✕</button>
                  </div>
                ))}
                <div className="flex justify-between pt-2 text-xl font-black text-orange-500 uppercase tracking-tight italic">
                  <span>Total</span>
                  <span>R$ {totalCart.toFixed(2).replace('.', ',')}</span>
                </div>
              </div>
            </div>

            <div className="space-y-4">
               <h3 className="text-zinc-500 font-black uppercase text-[10px] tracking-widest">Entrega:</h3>
               <input 
                 type="text" 
                 placeholder="Nome Completo" 
                 value={customer.name}
                 onChange={(e) => setCustomer({...customer, name: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-600"
               />
               <input 
                 type="tel" 
                 placeholder="Telefone" 
                 value={customer.phone}
                 onChange={(e) => setCustomer({...customer, phone: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-600"
               />
               <textarea 
                 placeholder="Endereço de Entrega" 
                 value={customer.address}
                 onChange={(e) => setCustomer({...customer, address: e.target.value})}
                 className="w-full bg-zinc-900 border border-zinc-800 rounded-xl p-4 focus:outline-none focus:ring-1 focus:ring-orange-600"
                 rows={3}
               />
            </div>

            <button 
              onClick={handleSendOrder}
              className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-4 rounded-xl shadow-lg flex items-center justify-center space-x-3 uppercase tracking-widest text-xs"
            >
              <span>Finalizar no WhatsApp</span>
            </button>
          </div>
        )}
      </main>

      {/* Carrinho Flutuante */}
      {view === 'menu' && cart.length > 0 && (
        <div className="fixed bottom-6 left-6 right-6 z-40 max-w-md mx-auto">
          <button 
            onClick={() => setView('checkout')}
            className="w-full bg-orange-600 hover:bg-orange-700 text-white p-4 rounded-2xl shadow-2xl flex items-center justify-between animate-in fade-in slide-in-from-bottom duration-500"
          >
            <div className="flex items-center">
              <span className="bg-white text-orange-600 font-black w-7 h-7 flex items-center justify-center rounded-lg mr-3 text-xs">{cart.length}</span>
              <span className="font-black tracking-widest uppercase text-[10px]">Ver Carrinho</span>
            </div>
            <span className="text-lg font-black italic">R$ {totalCart.toFixed(2).replace('.', ',')}</span>
          </button>
        </div>
      )}
    </div>
  );
}
